import numpy as np
import time
import matplotlib.pyplot as plt
mpl_config = {
    'font.family': 'serif', # sans-serif
    'font.size': 20,
    'mathtext.fontset': 'cm',
}
plt.rcParams.update(mpl_config)
del mpl_config

model_name = "EAA"


def fibonacci(n):
    if not(type(n) == int) or n < 0:
        return
    if n == 0 or n == 1:
        return 1
    else:
        f = fibonacci(n - 1) + fibonacci(n - 2)
        return f


def gen_H_Harper_real(L, mu, V, beta, phi=0):
    Ham = np.zeros((L, L), dtype=np.complex128)
    for i in range(L - 1):
        Ham[i, i + 1] = 1 + mu * np.cos(2 * np.pi * (i + 1 + 0.5) * beta + phi)
    Ham[L - 1, 0] = 1 + mu * np.cos(2 * np.pi * (L + 0.5) * beta + phi)
    Ham += Ham.conj().T
    for i in range(L):
        Ham[i, i] = V * np.cos(2 * np.pi * (i + 1) * beta + phi)
    return Ham


if __name__ == '__main__':
    L = fibonacci(14)
    mu_array = np.linspace(0, 2.5, 250)
    V_array = np.linspace(0, 5, 250)
    beta = fibonacci(13) / fibonacci(14)
    phi = 0

    mFD = np.zeros((mu_array.shape[0], V_array.shape[0]))
    for i, mu in enumerate(mu_array):
        for j, V in enumerate(V_array):
            Ham = gen_H_Harper_real(L, mu, V, beta, phi)
            Energy, VecR = np.linalg.eig(Ham)
            VecR = np.abs(VecR) ** 4
            sIPR = np.sum(VecR, axis=0)
            mIPR = np.sum(sIPR) / L
            mFD[i, j] = - np.log(mIPR) / np.log(L)
        print(f'mu = {mu:.2f} ({i + 1} / {len(mu_array)})')
    np.savez(f'data/1.1_EAA_phase_diagram_L_{L}', mFD=mFD)

    with np.load(f'data/1.1_EAA_phase_diagram_L_{L}.npz') as data:
        mFD = data['mFD']
    fig, ax = plt.subplots(figsize=(4.2, 3.7))
    im = ax.pcolormesh(V_array, mu_array, mFD, cmap='jet', vmin=0.0, vmax=1.0)
    ax.set_xlabel("$V$", fontsize=19)
    ax.set_ylabel(r"$\mu$", fontsize=19)
    ax.set_xticks([0, 2, 4])
    ax.set_yticks([0, 1, 2])
    cbar = plt.colorbar(im, ax=ax, label=r"$\bar{\eta}$")
    cbar.set_ticks([0.0, 1.0])
